<script setup lang="ts">
import { Head, Link } from '@inertiajs/vue3';import { BarChart3, Eye, Heart, MapPin, MessageCircle, Share2, TrendingUp, Users } from '@lucide/vue';import { computed, onMounted, ref } from 'vue';import AppShell from '../../Layouts/AppShell.vue';
const days=ref(30),data=ref<any>(),loading=ref(false),error=ref('');const compact=(n:number)=>new Intl.NumberFormat('en',{notation:'compact',maximumFractionDigits:1}).format(n??0);
async function load(){loading.value=true;error.value='';try{const r=await fetch(`/api/v1/analytics/me?days=${days.value}`,{credentials:'same-origin',headers:{Accept:'application/json'}});const p=await r.json();if(!r.ok)throw new Error(p.message??'Unable to load analytics.');data.value=p.data}catch(e:any){error.value=e.message}finally{loading.value=false}}
const series=computed(()=>{const raw=data.value?.daily?.video_views??[];if(raw.length)return raw;return Array.from({length:days.value},(_,i)=>({date:new Date(Date.now()-(days.value-1-i)*86400000).toISOString().slice(0,10),value:0}))});const max=computed(()=>Math.max(1,...series.value.map((x:any)=>x.value)));
onMounted(load);
</script>
<template><Head title="Metrics & Analytics"/><AppShell><main class="analytics-page"><header><div><span><BarChart3/> CREATOR ANALYTICS</span><h1>Your performance</h1><p>Understand who is watching and what earns the strongest response.</p></div><div class="periods"><button v-for="option in [7,30,90]" :class="{active:days===option}" @click="days=option;load()">{{ option===7?'Weekly':option===30?'Monthly':'90 days' }}</button></div></header><p v-if="error" class="analytics-error">{{ error }}</p><div v-if="loading" class="analytics-loading">Loading your statistics…</div><template v-else-if="data"><section class="analytics-cards"><article><Eye/><small>Views this period</small><strong>{{ compact(data.period.views) }}</strong><span>{{ compact(data.period.video_views) }} video · {{ compact(data.period.profile_views) }} profile</span></article><article><TrendingUp/><small>Engagement rate</small><strong>{{ data.period.engagement_rate }}%</strong><span>{{ compact(data.period.interactions) }} interactions</span></article><article><Users/><small>Total followers</small><strong>{{ compact(data.totals.followers) }}</strong><span>{{ compact(data.totals.profile_views) }} lifetime profile views</span></article><article><Heart/><small>Total video likes</small><strong>{{ compact(data.totals.likes) }}</strong><span>{{ compact(data.totals.shares) }} shares</span></article></section>
<section class="analytics-panel chart-panel"><div class="panel-title"><div><small>VIEW TREND</small><h2>Views over time</h2></div><b>{{ days }} days</b></div><div class="bar-chart"><div v-for="point in series" :title="`${point.date}: ${point.value} views`"><i :style="{height:`${Math.max(3,point.value/max*100)}%`}"/><small v-if="series.length<=7">{{ new Date(point.date).toLocaleDateString('en',{weekday:'short'}) }}</small></div></div></section>
<div class="analytics-columns"><section class="analytics-panel"><div class="panel-title"><div><small>TOP CONTENT</small><h2>Most viewed posts</h2></div><Link href="/profile">View profile</Link></div><article v-for="(post,index) in data.top_videos" class="top-post"><b>{{ index+1 }}</b><div><strong>{{ post.caption }}</strong><small>{{ new Date(post.published_at).toLocaleDateString() }}</small></div><span><Eye/>{{ compact(post.views) }}</span><span><Heart/>{{ compact(post.likes) }}</span></article><p v-if="!data.top_videos.length" class="empty">Publish a post to begin measuring performance.</p></section><section class="analytics-panel"><div class="panel-title"><div><small>AUDIENCE</small><h2>Top locations</h2></div><MapPin/></div><article v-for="location in data.locations" class="location-row"><span><MapPin/>{{ location.city }}</span><b>{{ compact(location.views) }} views</b><i><em :style="{width:`${location.views/(data.locations[0]?.views||1)*100}%`}"/></i></article><p v-if="!data.locations.length" class="empty">Location insights appear as people view your profile.</p></section></div>
<section class="analytics-panel interaction-panel"><div class="panel-title"><div><small>INTERACTIONS</small><h2>How people responded</h2></div></div><div><article><Heart/><strong>{{ compact(data.period.likes) }}</strong><span>Likes</span></article><article><MessageCircle/><strong>{{ compact(data.period.comments) }}</strong><span>Comments</span></article><article><Share2/><strong>{{ compact(data.period.shares) }}</strong><span>Shares</span></article></div></section></template></main></AppShell></template>
<style scoped>.analytics-page{max-width:1250px;margin:auto;padding:32px}.analytics-page>header{display:flex;justify-content:space-between;align-items:flex-end}.analytics-page header span{display:flex;gap:6px;color:#1769ed;font-weight:800}.analytics-page h1{font-size:clamp(30px,5vw,50px);margin:6px 0}.analytics-page header p{color:#718096}.periods{display:flex;padding:4px;border-radius:12px;background:#e8eef5}.periods button{padding:9px 13px;border:0;border-radius:9px;background:transparent}.periods button.active{color:white;background:#1769ed}.analytics-cards{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin:24px 0}.analytics-cards article,.analytics-panel{padding:20px;border:1px solid #dce4ed;border-radius:17px;background:white}.analytics-cards svg{color:#1769ed}.analytics-cards small,.analytics-cards span{display:block;color:#718096}.analytics-cards strong{display:block;margin:7px 0;font-size:29px}.panel-title{display:flex;justify-content:space-between;align-items:center}.panel-title small{color:#1769ed;font-weight:800}.panel-title h2{margin:4px 0}.bar-chart{display:flex;height:220px;gap:4px;align-items:end;margin-top:20px}.bar-chart>div{display:flex;height:100%;flex:1;flex-direction:column;justify-content:flex-end;align-items:center}.bar-chart i{width:100%;max-width:22px;min-height:3px;border-radius:5px 5px 0 0;background:linear-gradient(#1769ed,#66c9fa)}.bar-chart small{font-size:9px}.analytics-columns{display:grid;grid-template-columns:3fr 2fr;gap:16px;margin:16px 0}.top-post{display:grid;grid-template-columns:30px 1fr auto auto;gap:12px;align-items:center;padding:13px 0;border-bottom:1px solid #e6ebf0}.top-post span{display:flex;gap:4px;color:#657388}.top-post svg{width:14px}.top-post small{display:block;color:#718096}.location-row{display:grid;grid-template-columns:1fr auto;gap:7px;padding:9px 0}.location-row span{display:flex;gap:5px}.location-row svg{width:15px}.location-row i{grid-column:1/-1;height:5px;border-radius:5px;background:#edf1f5}.location-row em{display:block;height:100%;border-radius:5px;background:#1769ed}.interaction-panel>div:last-child{display:grid;grid-template-columns:repeat(3,1fr);gap:15px}.interaction-panel article{display:grid;justify-items:center;padding:20px;border-radius:13px;background:#f5f8fc}.interaction-panel strong{font-size:25px}.empty,.analytics-loading{padding:30px;color:#718096;text-align:center}@media(max-width:760px){.analytics-page{padding:15px}.analytics-page>header{align-items:flex-start;flex-direction:column}.analytics-cards{grid-template-columns:1fr 1fr}.analytics-columns{grid-template-columns:1fr}.chart-panel{overflow:hidden}.bar-chart{height:150px}.top-post{grid-template-columns:25px 1fr auto}.top-post span:last-child{display:none}}@media(max-width:420px){.analytics-cards{grid-template-columns:1fr}.interaction-panel>div:last-child{grid-template-columns:1fr}}</style>
